function solve(n) {
    // Map to store the sums and the pairs that generate them.
    // Key: sum (x = a^3 + b^3)
    // Value: Set of unique pairs (a, b) that result in this sum.
    const sumsMap = new Map();

    // Since a^3 + b^3 <= n, we can determine the maximum value for b.
    // If a = 1, then b^3 <= n - 1. b <= cubeRoot(n - 1).
    // Since a >= 1 and a <= b, the maximum value for b is when a=b, so 2*b^3 <= n. b <= cubeRoot(n/2).
    // A safer upper bound for b is cubeRoot(n).
    const maxB = Math.floor(Math.cbrt(n));

    // Iterate over all possible pairs (a, b) such that 1 <= a <= b and a^3 + b^3 <= n.
    for (let a = 1; a <= maxB; a++) {
        const aCubed = a * a * a;

        // Start b from a to satisfy a <= b
        for (let b = a; ; b++) {
            const bCubed = b * b * b;
            const sum = aCubed + bCubed;

            if (sum > n) {
                break; // Sum exceeds n, so further increases in b will also exceed n.
            }

            // Store the sum and the pair {a, b}
            if (!sumsMap.has(sum)) {
                sumsMap.set(sum, new Set());
            }

            // Store the pair as a string to ensure uniqueness in the Set, 
            // although for a fixed sum, the pair (a, b) with a <= b is unique unless we consider permutations,
            // but the problem defines the pair as (a, b) with a <= b, so the pair itself is unique for a given sum 
            // unless another distinct pair generates the same sum.
            // We just need to count the number of *different* pairs.

            // Since we are iterating over a <= b, the pair (a, b) is uniquely identified by (a, b).
            // We use the Set to count how many unique pairs generate this sum.
            sumsMap.get(sum).add(`${a},${b}`);

            // Optimization: if the current 'a' is already too large such that 
            // even with the smallest 'b' (which is 'a'), the sum exceeds n, 
            // we can break the outer loop. This is implicitly handled by the b loop breaking,
            // but a check on 'a' alone might prune faster if we calculate a better bound for 'a'.
            // Max 'a' is when 2*a^3 <= n, so a <= cubeRoot(n/2).
        }
    }

    const goodNumbers = [];

    // Check which sums have at least two different pairs
    for (const [sum, pairs] of sumsMap.entries()) {
        if (pairs.size >= 2) {
            goodNumbers.push(sum);
        }
    }

    // Return the result sorted in ascending order
    return goodNumbers.sort((a, b) => a - b);
}

