        if (2 * aCubed > n) break

        // Start b from a to satisfy a <= b
        var b = a
        while (true) {
            val bCubed = b.toLong() * b.toLong() * b.toLong()
            val sum = aCubed + bCubed

            if (sum > n) {
                break // Sum exceeds n, so further increases in b will also exceed n.
            }

            // Increment the count for this sum
