import kotlin.math.cbrt

fun solve(n: Long): Array<Long> {
    // Map to store the sums and the number of unique pairs (a, b) that result in this sum.
    // Key: sum (x = a^3 + b^3)
    // Value: Count of unique pairs.
    val sumsMap = mutableMapOf<Long, Int>()

    // Since a^3 + b^3 <= n and a <= b, the smallest possible sum is 1^3 + 1^3 = 2.
    // The maximum value for b occurs when a=1, so 1 + b^3 <= n, b^3 <= n-1.
    // maxB is roughly floor(cbrt(n)).
    var maxB = cbrt(n.toDouble()).toLong() + 1

    // We iterate over all possible pairs (a, b) such that 1 <= a <= b and a^3 + b^3 <= n.
    var a = 1L
    while (true) {
        val aCubed = a * a * a

        // Optimization: if even with the smallest b=a, the sum exceeds n, we can stop iterating 'a'.
        if (aCubed * 2 > n) break

        var b = a
        while (true) {
            val bCubed = b * b * b
            val sum = aCubed + bCubed

            if (sum > n) {
                break // Sum exceeds n, so further increases in b will also exceed n.
            }

            // Store the sum and increment its count.
            // Since we iterate with a <= b, each pair (a, b) is unique in the iteration order.
            sumsMap[sum] = sumsMap.getOrDefault(sum, 0) + 1

            b++
        }
        a++
    }

    val goodNumbers = mutableListOf<Long>()

    // Check which sums have at least two different pairs
    for ((sum, count) in sumsMap) {
        if (count >= 2) {
            goodNumbers.add(sum)
        }
    }

    // Return the result sorted in ascending order
    goodNumbers.sort()
    return goodNumbers.toTypedArray()
}
